import { test, expect } from '@playwright/test';

/**
 * REQ-005: Complete Order
 * Type: Positive | Priority: High
 * Auto-generated by Multi-Agent PDF-Playwright Framework
 */

test.describe('REQ-005 - Complete Order', () => {
  test.afterEach(async ({ page }, testInfo) => {
    if (testInfo.status !== testInfo.expectedStatus) {
      await page.screenshot({ path: `reports/screenshots/${testInfo.title.replace(/[^a-z0-9]/gi, '_').substring(0,50)}.png` });
    }
  });

  test('Complete Order', async ({ page }) => {
    const appUrl = process.env.APP_URL || "https://www.saucedemo.com";
    await page.goto(appUrl);


    await page.locator("#user-name")
      .first()
      .fill(process.env.TEST_USERNAME || "testuser@example.com", { timeout: 10000 });


    await page.locator("#password")
      .first()
      .fill(process.env.TEST_PASSWORD || "Password123!", { timeout: 10000 });


    await page.locator("#login-button")
      .first()
      .click({ timeout: 10000 });


    await page.waitForLoadState('domcontentloaded');
    await expect(page.locator('html')).toBeVisible();

    await page.locator("#shopping_cart_container, a.shopping_cart_link, .shopping_cart_link")
      .first()
      .click({ timeout: 10000 });

    await page.waitForLoadState('domcontentloaded');

    await page.locator("button#checkout, button[data-test=\"checkout\"], button:has-text('Checkout')")
      .first()
      .click({ timeout: 10000 });


    await page.locator("input[name*=\"first\"], input[id*=\"first\"], input[placeholder*=\"First name\"], input[aria-label*=\"First name\"]")
      .first()
      .fill('Test', { timeout: 10000 });


    await page.locator("input[name*=\"last\"], input[id*=\"last\"], input[placeholder*=\"Last name\"], input[aria-label*=\"Last name\"]")
      .first()
      .fill('User', { timeout: 10000 });


    await page.locator("input[name*=\"postal\"], input[id*=\"postal\"], input[placeholder*=\"Postal code\"], input[aria-label*=\"Postal code\"]")
      .first()
      .fill('12345', { timeout: 10000 });


    await page.locator("button[id^=\"continue\"], button:has-text('Continue')")
      .first()
      .click({ timeout: 10000 });

    await expect(page.locator('html')).toBeAttached();

    await page.locator("button#finish, button[id^=\"finish\"], button:has-text('Finish')")
      .first()
      .click({ timeout: 10000 });

    await expect(page.locator('html')).toBeVisible();
  });
});